import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

const CourseCard = ({ course }) => {
  const navigate = useNavigate();
  const [downloading, setDownloading] = useState(false);
  const [downloadProgress, setDownloadProgress] = useState(0);
  const [showPreview, setShowPreview] = useState(false);

  const handleClick = () => {
    navigate(`/course/${course.id}`);
  };

  const handleDownload = async (e) => {
    e.stopPropagation();
    
    if (!course.downloadUrl) {
      alert('No download available for this course');
      return;
    }

    setDownloading(true);
    setDownloadProgress(0);

    try {
      const response = await fetch(course.downloadUrl);
      
      if (!response.ok) {
        throw new Error('Download failed');
      }

      const contentLength = response.headers.get('content-length');
      const total = parseInt(contentLength, 10);
      let loaded = 0;

      const reader = response.body.getReader();
      const chunks = [];

      while (true) {
        const { done, value } = await reader.read();
        
        if (done) break;
        
        chunks.push(value);
        loaded += value.length;
        
        if (total) {
          const progress = Math.round((loaded / total) * 100);
          setDownloadProgress(progress);
        }
      }

      const blob = new Blob(chunks);
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `${course.name.replace(/\s+/g, '-').toLowerCase()}-materials.zip`;
      document.body.appendChild(a);
      a.click();
      window.URL.revokeObjectURL(url);
      document.body.removeChild(a);

      if (course.onDownload) {
        course.onDownload(course.id);
      }

      setTimeout(() => {
        setDownloading(false);
        setDownloadProgress(0);
      }, 1000);

    } catch (error) {
      console.error('Download error:', error);
      alert('Download failed. Please try again.');
      setDownloading(false);
      setDownloadProgress(0);
    }
  };

  // ✅ FIXED: Quick View with proper data
  const handleQuickView = (e) => {
    e.stopPropagation();
    
    // Debug: Console mein dekho actual data
    console.log('Course Data:', course);
    
    // Saare possible data sources check kar raha hai
    const notesCount = course.notes || course.note_count || course.total_notes || course.stats?.notes || 0;
    const pyqsCount = course.pyqs || course.pyq_count || course.total_pyqs || course.stats?.pyqs || 0;
    const syllabusCount = course.syllabus ? 1 : 0;
    const labCount = course.lab_manual ? course.lab_manual : 0;
    const views = course.views || course.total_views || course.view_count || 0;
    const downloads = course.downloads || course.total_downloads || course.download_count || 0;
    
    // Agar course.onPreview hai to use karo, nahi to modal dikhao
    if (course.onPreview) {
      course.onPreview(course);
    } else {
      // Create preview modal
      const modal = document.createElement('div');
      modal.style.cssText = `
        position: fixed;
        top: 50%;
        left: 50%;
        transform: translate(-50%, -50%);
        background: white;
        padding: 2rem;
        border-radius: 20px;
        box-shadow: 0 25px 50px rgba(0,0,0,0.3);
        z-index: 9999;
        max-width: 450px;
        width: 90%;
        font-family: 'Inter', sans-serif;
        animation: slideIn 0.3s ease;
      `;
      
      // Add animation
      const style = document.createElement('style');
      style.innerHTML = `
        @keyframes slideIn {
          from {
            opacity: 0;
            transform: translate(-50%, -60%);
          }
          to {
            opacity: 1;
            transform: translate(-50%, -50%);
          }
        }
      `;
      document.head.appendChild(style);
      
      // Get course icon
      const courseIcon = getCourseIcon(course.name);
      
      modal.innerHTML = `
        <div style="text-align: center; margin-bottom: 1.5rem;">
          <div style="
            font-size: 3rem;
            background: linear-gradient(135deg, #4f46e5, #7c3aed);
            width: 80px;
            height: 80px;
            border-radius: 50%;
            display: flex;
            align-items: center;
            justify-content: center;
            margin: 0 auto 1rem;
            color: white;
          ">${courseIcon}</div>
          <h2 style="color: #1f2937; margin-bottom: 0.5rem; font-size: 1.5rem;">${course.name || 'Course Details'}</h2>
          <p style="color: #6b7280; font-size: 0.9rem;">${course.branch || ''} • Sem ${course.semester || 'All'}</p>
        </div>
        
        <div style="display: grid; grid-template-columns: repeat(2, 1fr); gap: 1rem; margin-bottom: 1.5rem;">
          <div style="background: #f3f4f6; padding: 1rem; border-radius: 12px; text-align: center;">
            <div style="font-size: 1.5rem; margin-bottom: 0.3rem;">📄</div>
            <div style="font-weight: 700; color: #1f2937;">${notesCount}</div>
            <div style="font-size: 0.8rem; color: #6b7280;">Notes</div>
          </div>
          <div style="background: #f3f4f6; padding: 1rem; border-radius: 12px; text-align: center;">
            <div style="font-size: 1.5rem; margin-bottom: 0.3rem;">📝</div>
            <div style="font-weight: 700; color: #1f2937;">${pyqsCount}</div>
            <div style="font-size: 0.8rem; color: #6b7280;">PYQs</div>
          </div>
          <div style="background: #f3f4f6; padding: 1rem; border-radius: 12px; text-align: center;">
            <div style="font-size: 1.5rem; margin-bottom: 0.3rem;">📋</div>
            <div style="font-weight: 700; color: #1f2937;">${syllabusCount ? '✅' : '❌'}</div>
            <div style="font-size: 0.8rem; color: #6b7280;">Syllabus</div>
          </div>
          <div style="background: #f3f4f6; padding: 1rem; border-radius: 12px; text-align: center;">
            <div style="font-size: 1.5rem; margin-bottom: 0.3rem;">🔬</div>
            <div style="font-weight: 700; color: #1f2937;">${labCount}</div>
            <div style="font-size: 0.8rem; color: #6b7280;">Lab Manuals</div>
          </div>
        </div>
        
        <div style="display: flex; justify-content: space-between; padding: 1rem 0; border-top: 1px solid #e5e7eb; border-bottom: 1px solid #e5e7eb; margin-bottom: 1.5rem;">
          <div style="text-align: center; flex: 1;">
            <div style="font-size: 1.2rem; color: #4f46e5;">👁️</div>
            <div style="font-weight: 600; color: #1f2937;">${views}</div>
            <div style="font-size: 0.7rem; color: #6b7280;">Views</div>
          </div>
          <div style="text-align: center; flex: 1;">
            <div style="font-size: 1.2rem; color: #10b981;">⬇️</div>
            <div style="font-weight: 600; color: #1f2937;">${downloads}</div>
            <div style="font-size: 0.7rem; color: #6b7280;">Downloads</div>
          </div>
        </div>
        
        <div style="display: flex; gap: 1rem;">
          <button onclick="window.location.href='/course/${course.id}'" style="
            flex: 1;
            padding: 0.8rem;
            background: #4f46e5;
            color: white;
            border: none;
            border-radius: 8px;
            font-weight: 600;
            cursor: pointer;
            transition: all 0.3s;
          " onmouseover="this.style.background='#4338ca'" onmouseout="this.style.background='#4f46e5'">
            View Course
          </button>
          <button onclick="this.parentElement.parentElement.parentElement.remove()" style="
            flex: 1;
            padding: 0.8rem;
            background: #f3f4f6;
            color: #4b5563;
            border: 1px solid #d1d5db;
            border-radius: 8px;
            font-weight: 600;
            cursor: pointer;
            transition: all 0.3s;
          " onmouseover="this.style.background='#e5e7eb'" onmouseout="this.style.background='#f3f4f6'">
            Close
          </button>
        </div>
      `;
      
      document.body.appendChild(modal);
      
      // Remove modal when clicking outside
      setTimeout(() => {
        const handleClickOutside = (e) => {
          if (!modal.contains(e.target)) {
            modal.remove();
            document.removeEventListener('click', handleClickOutside);
          }
        };
        document.addEventListener('click', handleClickOutside);
      }, 100);
    }
  };

  // ✅ Course icon based on name
  const getCourseIcon = (name) => {
    const nameLower = name?.toLowerCase() || '';
    if (nameLower.includes('btech') || nameLower.includes('b.tech')) return '💻';
    if (nameLower.includes('bca')) return '📱';
    if (nameLower.includes('bba')) return '📊';
    if (nameLower.includes('mba')) return '🎓';
    if (nameLower.includes('mca')) return '💼';
    if (nameLower.includes('b.com') || nameLower.includes('bcom')) return '💰';
    if (nameLower.includes('ba')) return '📖';
    return '📚';
  };

  // ✅ Format course name
  const formatCourseName = (name) => {
    if (!name) return '';
    if (name.toLowerCase().includes('btech') || name.toLowerCase().includes('b.tech')) {
      return name.replace(/btech|b.tech/i, 'B.Tech').trim();
    }
    if (name.toLowerCase().includes('bca')) return 'BCA';
    if (name.toLowerCase().includes('bba')) return 'BBA';
    if (name.toLowerCase().includes('mba')) return 'MBA';
    if (name.toLowerCase().includes('mca')) return 'MCA';
    return name;
  };

  // ✅ Format branch
  const formatBranch = (branch, courseName) => {
    if (!branch || branch === 'General' || branch === 'All') {
      if (courseName?.toLowerCase().includes('btech')) return 'Computer Science';
      if (courseName?.toLowerCase().includes('bca')) return 'Computer Applications';
      if (courseName?.toLowerCase().includes('bba')) return 'Business Administration';
      if (courseName?.toLowerCase().includes('mba')) return 'Business Administration';
      if (courseName?.toLowerCase().includes('mca')) return 'Computer Applications';
      return 'General';
    }
    return branch;
  };

  const styles = {
    card: {
      background: 'white',
      borderRadius: '12px',
      padding: '1.5rem',
      boxShadow: '0 4px 6px rgba(0, 0, 0, 0.1)',
      textAlign: 'center',
      transition: 'all 0.3s ease',
      cursor: 'pointer',
      border: '1px solid #e5e7eb',
      height: '100%',
      display: 'flex',
      flexDirection: 'column',
      justifyContent: 'space-between',
      position: 'relative',
      overflow: 'hidden'
    },
    cardIcon: {
      fontSize: '2.5rem',
      marginBottom: '1rem',
      transition: 'transform 0.3s'
    },
    cardTitle: {
      fontSize: '1.25rem',
      fontWeight: '600',
      color: '#1f2937',
      marginBottom: '0.5rem',
      lineHeight: '1.4'
    },
    cardBranch: {
      color: '#6b7280',
      fontSize: '0.9rem',
      marginBottom: '1rem'
    },
    codeBadge: {
      position: 'absolute',
      top: '10px',
      right: '10px',
      background: '#dbeafe',
      color: '#1d4ed8',
      padding: '3px 8px',
      borderRadius: '12px',
      fontSize: '0.7rem',
      fontWeight: '500'
    },
    tagsContainer: {
      display: 'flex',
      justifyContent: 'center',
      gap: '0.5rem',
      marginBottom: '1rem',
      flexWrap: 'wrap'
    },
    tag: {
      background: '#e0e7ff',
      color: '#4f46e5',
      padding: '0.25rem 0.75rem',
      borderRadius: '12px',
      fontSize: '0.75rem',
      fontWeight: '500',
      transition: 'all 0.3s'
    },
    stats: {
      display: 'flex',
      justifyContent: 'space-between',
      marginTop: '1rem',
      fontSize: '0.8rem',
      color: '#6b7280',
      padding: '0.5rem',
      background: '#f9fafb',
      borderRadius: '8px'
    },
    statItem: {
      display: 'flex',
      alignItems: 'center',
      gap: '0.25rem'
    },
    actionButtons: {
      display: 'flex',
      gap: '0.5rem',
      marginTop: '1rem'
    },
    primaryButton: {
      flex: 2,
      padding: '0.75rem',
      background: 'linear-gradient(90deg, #4f46e5, #7c3aed)',
      color: 'white',
      border: 'none',
      borderRadius: '8px',
      fontWeight: '600',
      fontSize: '0.9rem',
      cursor: 'pointer',
      transition: 'all 0.3s',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      gap: '0.5rem'
    },
    secondaryButton: {
      flex: 1,
      padding: '0.75rem',
      background: '#f3f4f6',
      color: '#4b5563',
      border: '1px solid #d1d5db',
      borderRadius: '8px',
      fontWeight: '500',
      fontSize: '0.9rem',
      cursor: 'pointer',
      transition: 'all 0.3s',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center'
    },
    downloadProgress: {
      position: 'absolute',
      bottom: 0,
      left: 0,
      right: 0,
      height: '4px',
      background: 'linear-gradient(90deg, #10b981, #34d399)',
      transition: 'width 0.3s',
      borderRadius: '0 0 12px 12px'
    },
    loadingOverlay: {
      position: 'absolute',
      top: 0,
      left: 0,
      right: 0,
      bottom: 0,
      background: 'rgba(255, 255, 255, 0.9)',
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      justifyContent: 'center',
      borderRadius: '12px',
      zIndex: 10
    },
    loadingText: {
      marginTop: '0.5rem',
      fontSize: '0.9rem',
      color: '#4b5563'
    },
    popularityBadge: {
      position: 'absolute',
      top: '10px',
      left: '10px',
      background: '#fef3c7',
      color: '#92400e',
      padding: '3px 8px',
      borderRadius: '12px',
      fontSize: '0.7rem',
      fontWeight: '500',
      display: 'flex',
      alignItems: 'center',
      gap: '0.25rem'
    }
  };

  // Popularity badge
  const getPopularityBadge = () => {
    const notes = course.notes || course.note_count || 0;
    const pyqs = course.pyqs || course.pyq_count || 0;
    const totalResources = notes + pyqs;
    if (totalResources > 50) return '🔥 Hot';
    if (totalResources > 30) return '⭐ Popular';
    if (totalResources > 15) return '📈 Trending';
    return null;
  };

  const popularityBadge = getPopularityBadge();
  const courseIcon = getCourseIcon(course.name);
  const formattedName = formatCourseName(course.name);
  const formattedBranch = formatBranch(course.branch, course.name);

  return (
    <div 
      style={styles.card} 
      onClick={handleClick}
      onMouseEnter={(e) => {
        e.currentTarget.style.transform = 'translateY(-5px)';
        e.currentTarget.style.boxShadow = '0 15px 30px rgba(79, 70, 229, 0.15)';
        e.currentTarget.style.borderColor = '#4f46e5';
      }}
      onMouseLeave={(e) => {
        e.currentTarget.style.transform = 'translateY(0)';
        e.currentTarget.style.boxShadow = '0 4px 6px rgba(0, 0, 0, 0.1)';
        e.currentTarget.style.borderColor = '#e5e7eb';
      }}
    >
      {/* Popularity Badge */}
      {popularityBadge && (
        <div style={styles.popularityBadge}>
          {popularityBadge}
        </div>
      )}

      {/* Course Code Badge */}
      {course.code && (
        <div style={styles.codeBadge}>
          {course.code}
        </div>
      )}

      {/* Download Progress Bar */}
      {downloading && (
        <div style={{ ...styles.downloadProgress, width: `${downloadProgress}%` }} />
      )}

      {/* Loading Overlay */}
      {downloading && (
        <div style={styles.loadingOverlay}>
          <div style={{ 
            width: '40px', 
            height: '40px', 
            border: '3px solid #e5e7eb',
            borderTop: '3px solid #4f46e5',
            borderRadius: '50%',
            animation: 'spin 1s linear infinite'
          }} />
          <div style={styles.loadingText}>
            Downloading... {downloadProgress}%
          </div>
        </div>
      )}

      <div>
        <div style={styles.cardIcon}>{courseIcon}</div>
        <h3 style={styles.cardTitle}>{formattedName}</h3>
        <p style={styles.cardBranch}>
          {formattedBranch} • Sem {course.semester || 'All'}
        </p>
        
        <div style={styles.tagsContainer}>
          {(course.notes || course.note_count) > 0 && (
            <span style={styles.tag}>📄 {course.notes || course.note_count || 0}+ Notes</span>
          )}
          {(course.pyqs || course.pyq_count) > 0 && (
            <span style={styles.tag}>📝 {course.pyqs || course.pyq_count || 0}+ PYQs</span>
          )}
          <span style={styles.tag}>📋 Syllabus</span>
          {course.lab_manual && <span style={styles.tag}>🔬 Lab Manual</span>}
        </div>
      </div>
      
      <div>
        <div style={styles.stats}>
          <div style={styles.statItem}>
            <span>📄</span>
            <span>{course.notes || course.note_count || 0}+ notes</span>
          </div>
          <div style={styles.statItem}>
            <span>📝</span>
            <span>{course.pyqs || course.pyq_count || 0}+ PYQs</span>
          </div>
        </div>
        
        <div style={styles.actionButtons}>
          <button 
            style={styles.secondaryButton}
            onClick={handleQuickView}
            title="Quick Preview"
            onMouseEnter={(e) => {
              e.currentTarget.style.background = '#e5e7eb';
              e.currentTarget.style.transform = 'translateY(-2px)';
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.background = '#f3f4f6';
              e.currentTarget.style.transform = 'translateY(0)';
            }}
          >
            👁️ Quick View
          </button>
          
          <button 
            style={styles.primaryButton}
            onClick={handleDownload}
            disabled={downloading}
            title="Download Materials"
            onMouseEnter={(e) => {
              if (!downloading) {
                e.currentTarget.style.background = 'linear-gradient(90deg, #4338ca, #6d28d9)';
                e.currentTarget.style.transform = 'translateY(-2px)';
              }
            }}
            onMouseLeave={(e) => {
              if (!downloading) {
                e.currentTarget.style.background = 'linear-gradient(90deg, #4f46e5, #7c3aed)';
                e.currentTarget.style.transform = 'translateY(0)';
              }
            }}
          >
            {downloading ? '⏳' : '⬇️'} Download
          </button>
        </div>
      </div>

      {/* CSS animations */}
      <style>
        {`
          @keyframes spin {
            0% { transform: rotate(0deg); }
            100% { transform: rotate(360deg); }
          }
          
          @keyframes slideIn {
            from {
              opacity: 0;
              transform: translate(-50%, -60%);
            }
            to {
              opacity: 1;
              transform: translate(-50%, -50%);
            }
          }
        `}
      </style>
    </div>
  );
};

export default CourseCard;
